import Vue from 'vue'
import App from './App.vue'

import ElementUI from 'element-ui'
import 'element-ui/lib/theme-chalk/index.css'
Vue.use(ElementUI)

import router from './router.js'
Vue.use(router)

import axios from 'axios' //引入axios
Vue.prototype.$axios = axios
axios.defaults.withCredentials = true

import common from "@/js/common.js"
Vue.prototype.common = common

import {
	VueJsonp
} from 'vue-jsonp'
Vue.use(VueJsonp)

Vue.config.productionTip = false

// 全局路由前置守卫
// 检查session判断是否登录，并传回登录的类型
// 未登录时访问主页，跳转至登录页面
// 已登录时访问登录页面，跳转至主页
router.beforeEach((to, from, next) => {
	axios.get(common.backendURL + '/api/user/checkLoginState').then(res => {
		if (res.data.code == 0 && (to.path != '/' && to.path != '/loginwithphone' &&
				to.path != '/register')) {
			next('/')
		} else if (res.data.code == 1 && to.path == '/') {
			if (res.data.data.enable) {
				next('/userend')
			} else {
				next('/index')
			}
		} else if (res.data.code == 1 && res.data.data.enable != null &&
			to.path.startsWith('/index')) {
			next('/userend')
		} else if (res.data.code == 1 && res.data.data.enable == null &&
			to.path.startsWith('/userend')) {
			next('/index')
		} else {
			next()
		}
	}).catch(err => {
		ElementUI.Message({
			message: '无法访问服务器',
			center: true,
			type: 'error',
			duration: 0
		})
	})
})

var vm_target = new Vue({
	router,
	render: h => h(App),
}).$mount('#app')