<template>
	<div>
		<div id="background"></div>
		<el-form ref="form" label-width="70px" :inline="true" class="login_container" :model="form" :rules="rules">
			<h3 class="login_title">系统登录</h3>
			<el-form-item label="用户名" prop="username">
				<el-input v-model="form.username" placeholder="请输入用户名"></el-input>
			</el-form-item>
			<el-form-item label="密码" prop="password">
				<el-input type="password" v-model="form.password" placeholder="请输入密码"></el-input>
			</el-form-item>
			<el-form-item>
				<el-checkbox style="margin-left: 155px;" v-model="checked" label="登录为管理员" name="type"></el-checkbox>
			</el-form-item>
			<el-form-item>
				<el-button style="margin-left: 33px; " type="text" @click="onClickLoginWithPhone">手机号登录</el-button>
			</el-form-item>
			<el-form-item>
				<el-button style="" type="success" @click="onClickRegister">注册</el-button>
			</el-form-item>
			<el-form-item>
				<el-button style="" type="primary" @click="onClickLogin">登录</el-button>
			</el-form-item>
		</el-form>
	</div>
</template>

<script>
	export default {
		data() {
			return {
				checked: false,
				form: {
					username: '',
					password: ''
				},
				rules: {
					username: [{
						required: true,
						trigger: 'blur',
						message: '请输入用户名'
					}],
					password: [{
						required: true,
						trigger: 'blur',
						message: '请输入密码'
					}]
				}
			}
		},
		methods: {
			onClickLogin() {
				this.$refs.form.validate(valid => {
					if (valid) {
						var url = this.checked ? '/api/manager/login' : '/api/user/login'
						this.$axios.post(this.common.backendURL + url, this.form).then(res => {
							if (res.data.code == 1) {
								this.$message.success(this.form.username + " 欢迎登录")
								if (this.checked) {
									this.$router.push('/index')
								} else {
									this.$router.push('/userend')
								}
							} else {
								this.$message.error(res.data.msg)
							}
						})
					}

				})

			},
			onClickLoginWithPhone() {
				this.$router.push('/loginwithphone')
			},
			onClickRegister() {
				this.$router.push('/register')
			}
		}
	}
</script>

<style scoped>
	#background {
		background-image: url("../assets/img_login/bg.jpg");
		min-width: 1024px;
		position: fixed;
		top: 0;
		left: 0;
		height: 100%;
		width: 100%;
		background-position: center 0;
		background-repeat: no-repeat;
		background-size: cover;
		z-index: -10;
	}

	.login_container {
		width: 350px;
		border: 1px solid #eaeaea;
		margin: 93px auto;
		padding: 35px 35px 15px 35px;
		border-radius: 15px;
		background-color: white;
		box-shadow: 0 0 25px #cac6c6;
		box-sizing: border-box;
	}

	.login_container .el-input {
		width: 198px;
	}

	.login_title {
		text-align: center;
		margin-bottom: 40px;
		color: #505458;
	}
</style>
