<template>
	<div class="main">
		<el-row>
			<el-col :span="12">
				<el-avatar :size="300" style="margin-left: 100px;margin-top: 20px;"
					src="https://cube.elemecdn.com/0/88/03b0d39583f48206768a7534e55bcpng.png">
				</el-avatar>
			</el-col>
			<el-col :span="12">
				<div style="padding: 10px;">
					<el-descriptions direction="vertical" :column="3" border>
						<span slot="title" style="font-size: 20px;">用户信息</span>
						<el-descriptions-item label="用户名">{{userprofile.username}}</el-descriptions-item>
						<el-descriptions-item label="姓名">{{userprofile.name}}</el-descriptions-item>
						<el-descriptions-item label="手机号">{{userprofile.phone}}</el-descriptions-item>
					</el-descriptions>
					<el-descriptions direction="vertical" :column="2" border>
						<el-descriptions-item label="居住地">{{profilepreferencesdestination}}</el-descriptions-item>
						<el-descriptions-item label="经纬度">{{profilepreferences.lng}},
							{{profilepreferences.lat}}</el-descriptions-item>
						<el-descriptions-item label="出勤地址" :span="2">{{profilepreferences.address}}</el-descriptions-item>
					</el-descriptions>
				</div>
			</el-col>
		</el-row>
		<el-divider></el-divider>

		<el-row>
			<el-col :span="12" style="">
				<div style="text-align: center;">
					<h3>修改密码</h3>
				</div>
				<div style="width: 300px;margin: 0 auto;">
					<el-form ref="editpasswordform" label-width="100px" :inline="false" :model="form" :rules="rules">
						<el-form-item label="旧密码" prop="oldpassword">
							<el-input v-model="form.oldpassword" type="password" placeholder="请输入旧密码">
							</el-input>
						</el-form-item>
						<el-form-item label="新密码" prop="password">
							<el-input type="password" v-model="form.password" placeholder="请输入新密码"></el-input>
						</el-form-item>
						<el-form-item label="确认密码" prop="checkpassword">
							<el-input type="password" v-model="form.checkpassword" placeholder="请确认密码">
							</el-input>
						</el-form-item>
						<el-form-item>
							<el-button style="margin-left: 103px;" type="primary" @click="onClickChangePassword">修改密码
							</el-button>
						</el-form-item>
					</el-form>
				</div>
			</el-col>
			<el-col :span="12">
				<div style="text-align: center;">
					<h3>换绑手机号</h3>
				</div>
				<div style="width: 400px;margin: 0 auto;">
					<el-form ref="editphoneform" label-width="100px" :inline="false" :model="form2" :rules="rules2">
						<el-form-item label="密码" prop="password">
							<el-input v-model="form2.password" type="password" placeholder="请输入密码"></el-input>
						</el-form-item>
						<el-form-item label="新手机号" prop="newphone">
							<el-input style="width: 178px;margin-right: 10px;" v-model="form2.newphone"
								placeholder="请输入新手机号"></el-input>
							<el-button @click="handleClickSendCaptcha" :disabled="sendButtonDisabled"
								style="width: 112px;display: inline-block">
								{{ countdown > 0 ? `${countdown}秒后重试` : '获取验证码' }}
							</el-button>
						</el-form-item>
						<el-form-item label="验证码" prop="captcha">
							<el-input v-model="form2.captcha" placeholder="请输入验证码"></el-input>
						</el-form-item>
						<el-form-item>
							<el-button style="margin-left: 188px;" type="primary" @click="onClickChangePhone">
								换绑手机号
							</el-button>
						</el-form-item>
					</el-form>
				</div>
			</el-col>
		</el-row>
		<el-divider></el-divider>
		<el-row>
			<el-col :span="12" style="">
				<div style="text-align: center;">
					<h3>偏好设置</h3>
				</div>
				<div style="width: 400px;margin: 0 auto;">
					<el-form ref="preferences" label-width="100px" :inline="false" :model="preferences" :rules="rules3">
						<el-form-item label="目的地" prop="destination">
							<el-cascader style="width: 100%;" :options="options" v-model="preferences.destination">
							</el-cascader>
							</el-input>
						</el-form-item>
						<el-form-item label="地址" prop="address">
							<el-autocomplete v-model="preferences.address" style="width: 100%;" :fetch-suggestions="querySearch"
								placeholder="请输入目的地名称并选择" :trigger-on-focus="false" @select="handleSelect"></el-autocomplete>
						</el-form-item>
						<el-form-item label="出行方式" prop="type">
							<el-select v-model="preferences.type" placeholder="请选择" style="width: 100%;">
								<el-option v-for="item in types" :key="item.value" :label="item.label" :value="item.value">
								</el-option>
							</el-select>
						</el-form-item>
						<el-form-item label="面积" prop="area">
							<el-input oninput="value=value.replace(/[^0-9.]/g,'')" placeholder="请输入面积" v-model="preferences.area">
								<template slot="append">平方米</template>
							</el-input>
						</el-form-item>
						<el-form-item label="装修风格" prop="decorationStyle">
							<el-radio-group v-model="preferences.decorationStyle">
								<el-radio label="简装修"></el-radio>
								<el-radio label="精装修"></el-radio>
							</el-radio-group>
						</el-form-item>
						<el-form-item label="户型" prop="houseType">
							<el-input-number size="small" v-model="preferences.rooms" :min="0" :max="10" label="房">
							</el-input-number>&nbsp;&nbsp;房<br>
							<el-input-number size="small" v-model="preferences.halls" :min="0" :max="10" label="厅">
							</el-input-number>&nbsp;&nbsp;厅<br>
							<el-input-number size="small" v-model="preferences.bathrooms" :min="0" :max="10" label="卫">
							</el-input-number>&nbsp;&nbsp;卫
						</el-form-item>
						<el-form-item label="房屋朝向" prop="orientation">
							<el-checkbox-group v-model="preferences.orientation">
								<el-checkbox label="北"></el-checkbox>
								<el-checkbox label="东"></el-checkbox>
								<el-checkbox label="南"></el-checkbox>
								<el-checkbox label="西"></el-checkbox>
							</el-checkbox-group>
						</el-form-item>
						<el-form-item>
							<el-button style="margin-left: 203px;" type="primary" @click="onClickChangePreferences">修改偏好
							</el-button>
						</el-form-item>
					</el-form>
				</div>
			</el-col>
			<el-col :span="12">
				<br><br><br>
				<div style="width: 400px; height: 400px;" v-show="empty">
					<el-empty :image-size="250" description="请在左侧选择小区以显示地图"></el-empty>
				</div>
				<transition name="el-zoom-in-center">
					<div v-show="!nomap">
						<img :src="mapaddress">
					</div>
				</transition>
			</el-col>
		</el-row>
	</div>
</template>

<script>
	import {
		regionData,
		CodeToText
	} from 'element-china-area-data'
	export default {
		data() {
			var validateDestination = (rule, value, callback) => {
				if (this.preferences.destination == null) {
					callback(new Error('请选择'));
				} else {
					callback()
				}
			}
			var validatePass = (rule, value, callback) => {
				this.$axios.get(this.common.backendURL + '/api/user/checkpassword?id=' + this.userprofile.id +
					'&password=' + this.form.oldpassword).then(res => {
					if (res.data.code == 1) {
						callback()
					}
					callback(new Error('旧密码错误'));
				})
			}
			var validatePass2 = (rule, value, callback) => {
				this.$axios.get(this.common.backendURL + '/api/user/checkpassword?id=' + this.userprofile.id +
					'&password=' + this.form2.password).then(res => {
					if (res.data.code == 1) {
						callback()
					}
					callback(new Error('旧密码错误'));
				})
			}

			var validateConfirmPassword = (rule, value, callback) => {
				if (this.form.checkpassword != this.form.password) {
					callback(new Error('密码与确认密码不一致'));
				}
				callback()
			}
			var validateNewPhone = (rule, value, callback) => {
				if (/^1(3|4|5|6|7|8)\d{9}$/.test(this.form2.newphone)) {
					this.$axios.get(this.common.backendURL + '/api/user/checkNewPhone?phone=' + this.form2.newphone)
						.then(res => {
							if (res.data.code == 1) {
								callback()
							} else {
								callback(new Error('手机号已被注册'))
							}
						})
				} else {
					callback(new Error('请输入正确的手机号'));
				}
			}

			return {
				types: [{ //出行方式
					value: 'driving',
					label: '驾车'
				}, {
					value: 'transit',
					label: '公交'
				}],
				mapaddress: '',
				empty: true,
				nomap: true,
				addresslist: [],
				options: regionData,
				countdown: 0,
				sendButtonDisabled: false,
				userprofile: {},
				form: {
					oldpassword: '',
					password: '',
					checkpassword: '',
				},
				form2: {
					password: '',
					newphone: '',
					captcha: '',
				},
				profilepreferences: {
					destination: []
				},
				//房屋特征向量【面积，精装修，室，厅，卫，朝东，朝南，朝西，朝北，经度，纬度】
				preferences: {
					destination: null,
					address: '',
					type: 'driving',
					lat: 0,
					lng: 0,
					area: "0",
					decorationStyle: '简装修',
					rooms: 0,
					halls: 0,
					bathrooms: 0,
					orientation: [],
				},
				rules: {
					oldpassword: [{
						required: true,
						validator: validatePass,
						trigger: 'blur',
						// message: '请输入用户名'
					}],
					password: [{
						required: true,
						trigger: 'blur',
						message: '请输入新密码'
					}],
					checkpassword: [{
						required: true,
						validator: validateConfirmPassword,
						trigger: 'blur',
						// message: '请确认密码'
					}],
				},
				rules2: {
					password: [{
						required: true,
						validator: validatePass2,
						trigger: 'blur',
						// message: '请输入用户名'
					}],
					newphone: [{
						required: true,
						trigger: 'blur',
						validator: validateNewPhone,
						// message: '请输入新密码'
					}],
					captcha: [{
						required: true,
						trigger: 'blur',
						message: '请输入验证码'
					}],
				},
				rules3: {
					destination: [{
						required: true,
						validator: validateDestination,
						trigger: 'blur',
						// message: '请选择'
					}],
					address: [{
						required: true,
						trigger: 'blur',
						message: '请选择地址'
					}],
					area: [{
						required: true,
						trigger: 'blur',
						message: '请输入期望面积'
					}],
					// houseType: [{
					// 	required: true,
					// 	trigger: 'blur',
					// 	message: '请输入户型'
					// }],
					orientation: [{
						required: true,
						trigger: 'blur',
						message: '请选择朝向'
					}],
				}
			}
		},
		mounted() {
			this.$emit('changeIndex', '个人信息')
		},
		activated() {
			this.$axios.get(this.common.backendURL + '/api/user/checkLoginState').then(res => {
				this.$axios.get(this.common.backendURL + '/api/user/getById?id=' + res.data.data.id).then(res => {
					this.userprofile = res.data.data
					if (this.userprofile.preferences != null) {
						this.profilepreferences = JSON.parse(this.userprofile.preferences)
					} else {
						this.profilepreferences = {
							destination: '未设定',
							address: '未设定',
						}
					}
				})
			})
		},
		methods: {
			onClickChangePreferences() {
				this.$refs.preferences.validate().then(valid => {
					if (valid) {
						this.$axios.post(this.common.backendURL + '/api/user/changePreferences', {
							id: this.userprofile.id,
							preferences: JSON.stringify(this.preferences)
						}).then(res => {
							if (res.data.code == 1) {
								this.$message.success('修改成功')
								this.profilepreferences = this.preferences
							} else {
								this.$message.error('修改失败')
							}
						})
					}
				})
			},
			querySearch(queryString, cb) { //请求百度api取得地址输入建议列表
				this.$jsonp('http://api.map.baidu.com/place/v2/suggestion?query=' + queryString +
						'&region=' + this.city + '&city_limit=true&output=json&ak=' + this.common.ak)
					.then((response) => {
						this.addresslist = response.result
						var results = [];
						for (var i = 0; i < this.addresslist.length; i++) {
							results[i] = {
								"value": this.addresslist[i].name,
								"index": i,
							};
						}
						// 调用 callback 返回建议列表的数据
						cb(results);
					})
			},
			handleSelect(item) {
				this.empty = false
				this.nomap = true
				this.preferences.lat = this.addresslist[item.index].location.lat
				this.preferences.lng = this.addresslist[item.index].location.lng
				this.mapaddress = 'http://api.map.baidu.com/staticimage/v2?ak=' + this.common.ak + '&center=' +
					this.preferences.lng + ',' + this.preferences.lat + '&width=500&height=500&zoom=16&copyright=1&markers=' + this
					.preferences
					.lng + ',' + this.preferences.lat
				this.common.setTime(() => {
					this.nomap = false
				}, 300)

			},
			handleClickSendCaptcha() {
				this.$refs.editphoneform.validateField('newphone', valid => {
					if (valid.length) {
						// this.$message.error('验证码发送失败')
					} else {
						this.sendButtonDisabled = true
						this.countdown = 60; // 开始倒计时
						const timer = setInterval(() => {
							if (this.countdown > 0) {
								this.countdown--;
							} else {
								clearInterval(timer); // 倒计时结束，清除定时器
							}
						}, 1000);
						this.$axios.get(this.common.backendURL + '/api/manager/sendCaptcha?phone=' + this.form2
							.newphone).then(res => {
							this.common.setTime(() => {
								this.sendButtonDisabled = false;
							}, 60000)
						})
					}
				})
			},
			onClickChangePhone() {
				this.$refs.editphoneform.validate(valid => {
					if (valid) {
						this.$axios.get(this.common.backendURL + '/api/user/userChangePhone?id=' + this.userprofile
							.id +
							'&newPhone=' + this.form2.newphone +
							'&captcha=' + this.form2.captcha).then(res => {
							if (res.data.code == 1) {
								this.$message.success(res.data.msg)
								this.userprofile.phone = this.form2.newphone
								this.form2.password = ''
								this.form2.newphone = ''
								this.form2.captcha = ''
								this.countdown = 0
								this.sendButtonDisabled = false
							} else {
								this.$message.error(res.data.msg)
							}
						})
					}
				})
			},
			onClickChangePassword() {
				this.$refs.editpasswordform.validate(valid => {
					if (valid) {
						this.$axios.post(this.common.backendURL + '/api/user/changePassword', {
							id: this.userprofile.id,
							password: this.form.password
						}).then(res => {
							if (res.data.code == 1) {
								this.$message.success('修改成功')
								this.form.oldpassword = ''
								this.form.password = ''
								this.form.checkpassword = ''
							} else {
								this.$message.error('修改失败')
							}
						})
					}
				})
			}
		},
		computed: {
			city() { //返回通过地区选择器选择的城市名
				return CodeToText[this.preferences.destination[1]] == '市辖区' ?
					CodeToText[this.preferences.destination[0]] : CodeToText[this.preferences.destination[1]]
			},
			profilepreferencesdestination() {
				if (this.profilepreferences.destination == '未设定') {
					return '未设定'
				}
				return CodeToText[this.profilepreferences.destination[0]] + (
					CodeToText[this.profilepreferences.destination[1]] == '市辖区' ? "" : CodeToText[this.profilepreferences
						.destination[1]]) + CodeToText[this.profilepreferences.destination[2]]
			}
		}
	}
</script>

<style scoped>
	.main {
		width: 1024px;
		margin: 0 auto;
		/* border: 2px solid rgb(64, 158, 255); */
		padding: 0 10px;
	}
</style>