<!-- 管理端导航头 -->
<template>
	<div class="main">
		<div class="date" style="width: 85px;">{{newTime}}
		</div>

		<div style="line-height: 60px;float: left;margin-left: 10px;">
			<el-button v-if="$route.path=='/index/house'" type="primary" @click="back">
				<i class="el-icon-caret-left"></i>返回
			</el-button>
		</div>


		<div class="user">
			<!-- <img src="@/assets/user.png" /> -->
			<el-avatar src="https://cube.elemecdn.com/0/88/03b0d39583f48206768a7534e55bcpng.png"></el-avatar>
			&nbsp;&nbsp;
			<span>{{username}}</span>&nbsp;&nbsp;
			<el-button type="danger" size="medium" @click="onClickLogout">退出登录</el-button>
		</div>

		<!-- 		<div style="line-height: 60px;float: right;margin-right: 10px;">
			<el-button v-if="$route.path=='/index/house'" type="primary" @click="back">
				< 返回</el-button>
		</div>
		 -->
	</div>
</template>

<script>
	export default {
		data() {
			return {
				username: '',
				newTime: '',
			}
		},
		created() {
			this.$axios.get(this.common.backendURL + '/api/user/checkLoginState').then(res => {
				this.username = res.data.data.username
			})
		},
		mounted() {
			this.getNowTime(); //进入页面调用该方法获取当前时间
			clearInterval(myTimeDisplay); //销毁之前定时器
			var myTimeDisplay = setInterval(() => {
				this.getNowTime(); //每秒更新一次时间
			}, 1000);
		},
		methods: {
			onClickLogout() {
				this.$axios.get(this.common.backendURL + '/api/user/logout').then(res => {
					if (res.data.code == 1) {
						this.$message.success("欢迎下次登录")
						this.$router.push('/login')
					}
				})
			},
			getNowTime() {
				var date = new Date();
				var time = date.getHours() + ':' + this.addZero(date.getMinutes()) + ':' + this.addZero(date.getSeconds());
				this.newTime = time;
			},
			addZero(s) {
				return s < 10 ? ('0' + s) : s;
			},
			back() {
				this.$router.back()
			}
		}
	}
</script>

<style scoped>

	.date {
		float: left;
		font-size: 20px;
		color: rgb(64, 158, 255);
		line-height: 60px;
		height: 60px;
		font-weight: bold;
		margin-left: 10px;
	}


	.user {
		float: right;
		margin-right: 10px;
		height: 60px;
		line-height: 60px;
	}


	/* 图片对齐方式 */
	.user img {
		vertical-align: middle;
	}

	.el-avatar {
		vertical-align: middle;
	}
</style>
