import Vue from 'vue'
import VueRouter from 'vue-router'
import Login from './views/Login.vue'
import LoginWithPhone from './views/LoginWithPhone.vue'
import Main from './views/Main.vue'
import UserEndMain from './views/UserEndMain.vue'
import UserManagement from './components/UserManagement.vue'
import HouseManagement from './components/HouseManagement.vue'
import AddHouse from './components/AddHouse.vue'
import UserFindHouse from './components/UserFindHouse.vue'
import UserCollection from './components/UserCollection.vue'
import UserOrder from './components/UserOrder.vue'
import UserProfile from './components/UserProfile.vue'
import UserAddHouse from './components/UserAddHouse.vue'

Vue.use(VueRouter)

const originalPush = VueRouter.prototype.push
VueRouter.prototype.push = function push(location) {
	return originalPush.call(this, location).catch(err => err)
}



export default new VueRouter({
	routes: [{
			path: '/',
			component: Login
		},
		{
			path: '/loginwithphone',
			component: LoginWithPhone
		},
		{
			path: '/register',
			component: () => import('./views/Register.vue')
		},
		{
			path: '/index',
			redirect: '/index/usermng',
			component: Main,
			children: [{
					path: 'usermng',
					component: UserManagement,
				},
				{
					path: 'housemng',
					component: HouseManagement,

				},
				{
					path: 'addhouse',
					component: AddHouse,
				},
				{
					path: 'ordermng',
					component: () => import('./components/OrderManagement.vue'),
				},
				{
					path: 'house',
					name: 'house',
					component: () => import('./views/HouseInfo.vue'),
				},

			]
		},
		{
			path: '/userend',
			redirect: '/userend/userfindhouse',
			component: UserEndMain,
			children: [{
					path: 'userfindhouse',
					component: UserFindHouse,
				},
				{
					path: 'usercollection',
					component: UserCollection,
				},
				{
					path: 'userorder',
					component: UserOrder,
				},
				{
					path: 'userhouse',
					name: 'userhouse',
					component: () => import('./views/HouseInfo.vue'),
				},
				{
					path: 'userprofile',
					component: UserProfile,
				},
				{
					path: 'useraddhouse',
					component: UserAddHouse
				},
			]
		},
	]
})