<template>
	<div>
		<div id="background"></div>
		<el-form ref="form" label-width="70px" :inline="true" class="login_container" :model="form" :rules="rules">
			<h3 class="login_title">系统登录</h3>
			<el-form-item label="手机号" prop="phone">
				<el-input class="phone" v-model="form.phone" placeholder="请输入手机号"></el-input>
			</el-form-item>
			<el-form-item>
				<el-button @click="handleClick" :disabled="sendButtonDisabled" style="width: 112px;">
					{{ countdown > 0 ? `${countdown}秒后重试` : '获取验证码' }}
				</el-button>
			</el-form-item>
			<el-form-item label="验证码" prop="captcha">
				<el-input class="password" type="captcha" v-model="form.captcha" placeholder="请输入验证码"></el-input>
			</el-form-item>
			<el-form-item>
				<el-checkbox style="margin-left: 210px;" v-model="checked" label="登录为管理员" name="type"></el-checkbox>
			</el-form-item>
			<el-form-item>
				<el-button style="margin-left: 90px;" type="text" @click="onClickLoginWithUsername">用户名登录
				</el-button>
			</el-form-item>
			<el-form-item>
				<el-button style="" type="success" @click="onClickRegister">注册</el-button>
			</el-form-item>
			<el-form-item>
				<el-button style="" type="primary" @click="clickLogin">登录</el-button>
			</el-form-item>
		</el-form>
	</div>
</template>

<script>
	export default {
		data() {
			return {
				countdown: 0,
				checked: false,
				sendButtonDisabled: false,
				sendButtonMsg: '发送验证码',
				form: {
					phone: '',
					captcha: ''
				},
				rules: {
					phone: [{
							required: true,
							trigger: 'blur',
							message: '请输入手机号'
						},
						{
							pattern: /^1(3|4|5|6|7|8)\d{9}$/,
							message: '请输入正确的手机号'
						}
					],
					captcha: [{
						required: true,
						trigger: 'blur',
						message: '请输入验证码'
					}]
				}
			}
		},
		methods: {
			handleClick() {
				if (/^1(3|4|5|6|7|8)\d{9}$/.test(this.form.phone)) {
					// if (this.countdown > 0) {
					//   return; // 如果倒计时仍在进行，则不执行任何操作
					// }
					// TODO：发送验证码的请求
					this.sendButtonDisabled = true
					this.countdown = 60; // 开始倒计时
					const timer = setInterval(() => {
						if (this.countdown > 0) {
							this.countdown--;
						} else {
							clearInterval(timer); // 倒计时结束，清除定时器
						}
					}, 1000);
					this.$axios.get(this.common.backendURL + '/api/manager/sendCaptcha?phone=' + this.form.phone).then(
						res => {

							// this.sendButtonMsg = '1分钟后重试'
							this.common.setTime(() => {
								this.sendButtonDisabled = false;
								// this.sendButtonMsg = '发送验证码';
							}, 60000)
						})
				} else {
					this.$message.error('请输入正确的手机号')
				}
			},
			clickLogin() {
				this.$refs.form.validate(valid => {
					if (valid) {
						var url = this.checked ? '/api/manager/checkCaptcha' : '/api/user/checkCaptcha'
						this.$axios.get(this.common.backendURL + url + '?phone=' + this.form.phone + '&captcha=' +
							this.form
							.captcha + '&register=false').then(res => {
							if (res.data.code == 1) {
								this.$message.success(this.form.phone + " 欢迎登录")
								if (this.checked) {
									this.$router.push('/index')
								} else {
									this.$router.push('/userend')
								}
							} else {
								this.$message.error(res.data.msg)
							}
						})
					}

				})

			},
			onClickLoginWithUsername() {
				this.$router.push('/')
			},
			onClickSendCaptcha() {

			},
			onClickRegister() {
				this.$router.push('/register')
			}
		}
	}
</script>

<style scoped>
	#background {
		background-image: url("../assets/img_login/bg.jpg");
		min-width: 1024px;
		position: fixed;
		top: 0;
		left: 0;
		height: 100%;
		width: 100%;
		background-position: center 0;
		background-repeat: no-repeat;
		background-size: cover;
		z-index: -10;
	}

	.login_container {
		width: 420px;
		border: 1px solid #eaeaea;
		margin: 93px auto;
		padding: 35px 35px 15px 35px;
		border-radius: 15px;
		background-color: #fff;
		box-shadow: 0 0 25px #cac6c6;
		box-sizing: border-box;
	}

	.login_container .password {
		width: 252px;
	}

	.login_container .phone {
		width: 130px;
	}

	.login_title {
		text-align: center;
		margin-bottom: 40px;
		color: #505458;
	}
</style>
