<!-- 管理端左侧导航菜单 -->
<template>
	<div>
		<el-menu :default-openeds="openeds" :default-active="active" class="el-menu-vertical-demo"
			background-color="#545c64" text-color="#fff" active-text-color="#ffd04b">
			<h3 style="text-align: center;color: white;">房屋租赁管理系统</h3>

			<el-menu-item v-for="item in noChildren" :index="item.name" @click="clickMenu(item)">
				<i :class="`el-icon-${item.icon}`"></i>
				<span slot="title">{{item.label}}</span>
			</el-menu-item>

			<el-submenu v-for="item in hasChildren" :index="item.name">
				<template slot="title">
					<i :class="`el-icon-${item.icon}`"></i>
					<span slot="title">{{item.label}}</span>
				</template>
				<el-menu-item-group>
					<el-menu-item v-for="child in item.children" :index="child.name" @click="clickMenu(child)">
						{{child.label}}
					</el-menu-item>
				</el-menu-item-group>
			</el-submenu>

		</el-menu>
	</div>
</template>

<script>
	export default {
		data() {
			return {
				openeds: ['房源管理'], //导航菜单默认展开项
				active: '用户管理',
				menuData: [{
						path: '/index/usermng',
						name: '用户管理',
						label: '用户管理',
						icon: 'user-solid',
					},
					{
						label: '房源管理',
						name: '房源管理',
						icon: 's-home',
						children: [{
								path: '/index/housemng',
								name: '管理房源',
								label: '管理房源',
							},
							{
								path: '/index/addhouse',
								name: '添加房源',
								label: '添加房源',
							}
						]
					},
					{
						path: '/index/ordermng',
						name: '订单管理',
						label: '订单管理',
						icon: 's-order',
					},
					// {	
					// 	name: 'other',
					// 	label: "其他",
					// 	icon: "location",
					// 	children: [
					// 		{
					// 			path: '/p1',
					// 			name: 'p1',
					// 			label: 'p1',
					// 			icon: 'setting',	
					// 		},
					// 		{
					// 			path: '/p2',
					// 			name: 'p2',
					// 			label: 'p2',
					// 			icon: 'setting',
					// 		}
					// 	]
					// }
				],

			}
		},
		computed: {
			noChildren() {
				return this.menuData.filter(item => !item.children)
			},
			hasChildren() {
				return this.menuData.filter(item => item.children)
			}
		},
		methods: {
			clickMenu(item) {
				this.$router.push(item.path)
			},
			changeIndex(index) {
				this.active = index
			}
		}
	}
</script>

<style scoped>
	.el-menu {
		height: 100vh;
		border: 0;
	}

	::-webkit-scrollbar {
		display: none;
	}
</style>