<template>
	<div class="main">
		<div style="margin-left: 10px;font-size: 20px;margin-bottom: 20px;">我的订单</div>
		<div v-for="(item,index) in orderData">
			<div class="ordercard"
				style="height: 262px;width: 510px;float: left; margin-bottom: 20px;margin-right: 20px; box-shadow: 0 2px 12px 0 rgba(0,0,0,0.1);">
				<div style="width: fit-content;float: left;" class="info">
					<transition name="el-zoom-in-center">
						<one-house v-if="show" :index="index"></one-house>
					</transition>
				</div>
				<div style="float: left;height: 100%;width: calc(100% - 242px)">
					<el-descriptions :column="1" border labelStyle="width:100px;">
						<el-descriptions-item>
							<template slot="label">
								租期
							</template>
							<el-tag><b>{{item.duration}}</b></el-tag> 个月
						</el-descriptions-item>
						<el-descriptions-item>
							<template slot="label">
								状态
							</template>
							<b>
							<el-tag type="warning" v-if="item.orderStatus==0">待确认</el-tag>
							<el-tag v-if="item.orderStatus==1">已确认</el-tag>
							<el-tag type="success" v-if="item.orderStatus==2">已生效</el-tag>
							<el-tag type="info" v-if="item.orderStatus==3">已取消</el-tag>
							</b>
						</el-descriptions-item>
						<el-descriptions-item>
							<template slot="label">
								订单号
							</template>
							{{item.id}}
						</el-descriptions-item>
				<el-descriptions-item>
						<template slot="label">
							下单时间
						</template>
						{{item.orderTime}}
					</el-descriptions-item>
					
					</el-descriptions>
					<!-- <div style="height: 155px;"></div> -->
					<div style="padding:15px 10px 0 10px;">
						<el-button size="small"  style="float: right;" :disabled="item.orderStatus!=0" @click="onClickCancelOrder(item.id,index)">取消</el-button>
					</div>
				</div>
			</div>
		</div>
	</div>

</template>

<script>
	import OneHouse from '../components/OneHouse.vue'
	export default {
		mounted() {
			this.$emit('changeIndex', '订单管理')
		},
		data() {
			return {
				orderData: [],
				housesData: [],
				show: false,
			}
		},
		activated() {
			this.show = false
			this.$axios.get(this.common.backendURL + '/api/order/listUserOrders').then(res => {
				this.orderData = res.data.orders
				this.housesData = res.data.houses
				this.show = true
			})
		},
		methods: {
			onClickCancelOrder(id,index) {
				this.$axios.get(this.common.backendURL + '/api/order/cancelOrder?orderId=' + id).then(res => {
					if (res.data.code == 1) {
						this.orderData[index].orderStatus = 3
						this.$message.success('取消成功')
					}
				})
			}
		},
		components: {
			OneHouse
		}
	}
</script>

<style scoped>
	.main {
		width: 1060px;
		margin: 0 auto;
	}

	.info {
		transition: 0.3s;
		/* 设置变换的过渡时间为0.3秒 */
	}

	.info:hover {
		/* 当鼠标悬停在图片上时 */
		transform: scale(1.1);
		/* 让图片放大1.1倍 */
	}
</style>