<template>
	<div style="width: 100%;height: 100%;min-width: 1024px;">
		<!-- 	<h3>用户端</h3>
	 -->
		<el-container>
			<el-header style="background-color: #fff;">
				<div style="display: inline-block;">
					<el-menu :default-active="active" class="el-menu-demo" mode="horizontal">
						<el-menu-item v-for="item in noChildren" :index="item.name" @click="clickMenu(item)">
							<i :class="`el-icon-${item.icon}`"></i>
							<span slot="title">{{item.label}}</span>
						</el-menu-item>
						<el-submenu v-for="item in hasChildren" :index="item.name">
							<template slot="title">
								<i :class="`el-icon-${item.icon}`"></i>
								<span slot="title">{{item.label}}</span>
							</template>
							<el-menu-item-group>
								<el-menu-item v-for="child in item.children" :index="child.name" @click="clickMenu(child)">
									{{child.label}}
								</el-menu-item>
							</el-menu-item-group>
						</el-submenu>
					</el-menu>
				</div>
				<div style="display: inline-block; line-height: 60px;float: right;margin-right: 10px;">
					<el-button @click="onClickLogout" style="margin-top: 10px;">
						<i class="el-icon-switch-button"></i> 退出登录
					</el-button>
				</div>
			</el-header>
			<el-main>
				<keep-alive>
					<router-view @changeIndex="changeIndex"></router-view>
				</keep-alive>

			</el-main>
		</el-container>
	</div>
</template>

<script>
	export default {
		activated() {},
		data() {
			return {
				name: 'UserEndMain',
				active: '寻找房源',
				menuData: [{
						path: '/userend/userfindhouse',
						name: '寻找房源',
						label: '寻找房源',
						icon: 's-home',
					},
					{
						path: '/userend/useraddhouse',
						name: '发布房源',
						label: '发布房源',
						icon: 's-home',
					},
					{
						path: '/userend/usercollection',
						name: '我的收藏',
						label: '我的收藏',
						icon: 'star-on',
					},
					{
						path: '/userend/userorder',
						name: '订单管理',
						label: '订单管理',
						icon: 's-order',
					},
					{
						path: '/userend/userprofile',
						name: '个人信息',
						label: '个人信息',
						icon: 'user-solid',
					},
				],
			}
		},
		methods: {
			onClickLogout() {
				this.$axios.get(this.common.backendURL + '/api/user/logout').then(res => {
					if (res.data.code == 1) {
						this.$message.success("欢迎下次登录")
						this.$router.push('/login')
					}
				})
			},
			// onClickProfile() {
			// 	this.$router.push('/userend/userprofile')
			// },
			clickMenu(item) {
				this.$router.push(item.path)
			},
			changeIndex(index) {

				this.active = index

			}
		},
		computed: {
			noChildren() {
				return this.menuData.filter(item => !item.children)
			},
			hasChildren() {
				return this.menuData.filter(item => item.children)
			}
		}
	}
</script>

<style scoped>
	.el-header {
		/* background-color: rgb(236,245,255); */
		box-shadow: 0 0 25px #cac6c6;
		padding: 0;
		position: fixed;
		width: 100%;

		left: 0;
		top: 0;
		z-index: 1000;
	}


	.el-main {
		/* overflow: auto; */
		/* height: 92vh; */
		margin-top: 60px;
	}
</style>