<template>
	<div>
		<el-drawer title="筛选房源" size="40%" :visible.sync="drawer" :direction="direction" :before-close="handleClose">

			<el-form ref="form" label-width="80px" :inline="true" :model="query">
				<el-form-item label="所在地">
					<el-cascader :disabled="cascaderDisabled" :options="options" v-model="query.selectedOptions"></el-cascader>
				</el-form-item>


				<el-form-item label="装修风格">
					<el-radio-group v-model="query.decorationStyle">
						<el-radio-button label="全部"></el-radio-button>
						<el-radio-button label="简装修"></el-radio-button>
						<el-radio-button label="精装修"></el-radio-button>
					</el-radio-group>
				</el-form-item>
				<el-form-item label="户型" style="margin-right: 100px;">
					<el-input oninput="value=value.replace(/[^0-9]/g,'')" v-model="query.rooms" maxlength="1" label="房"
						placeholder="不限" style="width: 60px;">
					</el-input>&nbsp;&nbsp;&nbsp;&nbsp;房&nbsp;&nbsp;
					<el-input oninput="value=value.replace(/[^0-9]/g,'')" v-model="query.halls" maxlength="1" label="厅"
						placeholder="不限" style="width: 60px;">
					</el-input>&nbsp;&nbsp;&nbsp;&nbsp;厅
					<el-input oninput="value=value.replace(/[^0-9]/g,'')" v-model="query.bathrooms" maxlength="1" label="卫"
						placeholder="不限" style="width: 60px;">
					</el-input>&nbsp;&nbsp;&nbsp;&nbsp;卫
				</el-form-item>

				<!-- 	<el-form-item label="状态" style="margin-right: 200px;">
				<el-radio-group v-model="query.status">
					<el-radio label="全部"></el-radio>
					<el-radio label="待审核"></el-radio>
					<el-radio label="已发布"></el-radio>
					<el-radio label="已租出"></el-radio>
					<el-radio label="已锁定"></el-radio>
				</el-radio-group>
			</el-form-item> -->

				<el-form-item label="租金">
					<el-slider v-model="query.price" :show-tooltip="false" range :marks="marks"
						style="width: 800px;margin-left: 10px;" :max="16000" :step="1000">
					</el-slider>
				</el-form-item>

			</el-form>
		</el-drawer>
		<div class="search">
			<el-button @click="onClickDrawer" type="primary">筛选</el-button>
			<el-input class="input" @change="handleInputChange" placeholder="搜索小区名/发布人..." v-model="queryString">
				<el-button slot="append" icon="el-icon-search"></el-button>
			</el-input>

			<el-radio-group v-model="query.by" @change="handleInputChange"
				style="margin-left: 20px;float: right;margin-right: 10px;">
				<el-radio-button label="发布时间"></el-radio-button>
				<el-radio-button label="价格"></el-radio-button>
				<el-radio-button label="面积"></el-radio-button>
				<el-radio-button label="通勤时间"></el-radio-button>
			</el-radio-group>
			<el-radio-group v-model="query.order" @change="handleInputChange" style="margin-left: 20px;float: right;">
				<el-radio-button label="升序"></el-radio-button>
				<el-radio-button label="降序"></el-radio-button>
			</el-radio-group>
			<i class="el-icon-sort" style="float: right;line-height: 40px;"></i>
		</div>
		<div class="infotable">
			<div class="info" v-for="(item,index) in housesData">
				<transition name="el-zoom-in-center">
					<one-house v-if="show" :index="index"></one-house>
				</transition>
			</div>
		</div>
		<div class="page">
			<el-pagination align="center" @current-change="handleCurrentChange" :current-page="currentPage"
				:page-size="pageSize" layout="total, prev, pager, next" :total="total"></el-pagination>
		</div>
		<recommended-listing></recommended-listing>
	</div>
</template>

<script>
	import OneHouse from '../components/OneHouse.vue'
	import RecommendedListing from '../components/RecommendedListing.vue'
	import {
		regionDataPlus
	} from 'element-china-area-data'
	export default {
		data() {
			return {
				cascaderDisabled: false,
				options: regionDataPlus,
				query: { //筛选项
					price: [0, 16000], //租金
					selectedOptions: [''], //所在地
					decorationStyle: '全部',
					rooms: '',
					halls: '',
					bathrooms: '',
					status: '已发布',
					order: '降序',
					by: '发布时间',
				},
				marks: {
					0: '0',
					1000: '1000',
					2000: '2000',
					3000: '3000',
					4000: '4000',
					5000: '5000',
					6000: '6000',
					7000: '7000',
					8000: '8000',
					9000: '9000',
					10000: '10000',
					11000: '11000',
					12000: '12000',
					13000: '13000',
					14000: '14000',
					15000: '15000',
					16000: {
						style: {
							fontSize: '30px',
						},
						label: this.$createElement('span', '∞')
					},
				},
				drawer: false,
				direction: 'ttb',
				queryString: '',
				currentPage: 1,
				pageSize: 8,
				total: 0,
				housesData: [],
				show: false,
			}
		},
		activated() {
			this.show = false
			this.$axios.post(`${this.common.backendURL}/api/house/data?curPage=${this.currentPage}&limit=${this.pageSize}
			`, this.postform).then(res => {
				if (res.data.msg != '0') {
					this.total = parseInt(res.data.msg)
					this.housesData = res.data.data
					this.common.setTime(() => {
						this.show = true
					}, 200)
				} else {
					this.$message.error('无相关房源')
				}
			})
			
			
		},
		computed: {
			postform() {
				return {
					order: this.postorder,
					by: this.postby,
					queryString: this.queryString,
					priceStart: this.query.price[0],
					priceEnd: this.query.price[1],
					province: this.query.selectedOptions[0],
					city: this.query.selectedOptions[1],
					region: this.query.selectedOptions[2],
					decorationStyle: this.decorationstyle,
					rooms: this.query.rooms == '' ? -1 : parseInt(this.query.rooms),
					halls: this.query.halls == '' ? -1 : parseInt(this.query.halls),
					bathrooms: this.query.bathrooms == '' ? -1 : parseInt(this.query.bathrooms),
					status: this.computedstatus,
				}
			},
			decorationstyle() {
				if (this.query.decorationStyle == '简装修') {
					return 0
				} else if (this.query.decorationStyle == '精装修') {
					return 1
				}
				return 2
			},
			computedstatus() {
				if (this.query.status == '待审核') {
					return 0
				} else if (this.query.status == '已发布') {
					return 1
				} else if (this.query.status == '已租出') {
					return 2
				} else if (this.query.status == '已锁定') {
					return 3
				}
				return 4
			},
			postorder() {
				return this.query.order == '升序' ? 'asc' : 'desc'
			},
			postby() {
				return this.query.by == '发布时间' ? 'add_time' : this.query.by == '价格' ? 'price' : this.query.by == '通勤时间' ?
					'time' : 'area'
			},
		},
		methods: {
			handleCurrentChange(val) {
				this.show = false
				this.currentPage = val;
				this.$axios.post(`${this.common.backendURL}/api/house/data?curPage=${val}&limit=${this.pageSize}
			`, this.postform).then(res => {
					if (res.data.msg != "0") {
						this.total = parseInt(res.data.msg)
						this.housesData = res.data.data
						this.common.setTime(() => {
							this.show = true
						}, 200)
					} else {
						this.$message.error('无相关房源')
					}
				})
			},
			handleInputChange() {
				this.show = false
				this.currentPage = 1;
				this.$axios.post(`${this.common.backendURL}/api/house/data?curPage=1&limit=${this.pageSize}
			`, this.postform).then(res => {
					if (res.data.msg != "0") {
						this.total = parseInt(res.data.msg)
						this.housesData = res.data.data
						this.common.setTime(() => {
							this.show = true
						}, 200)
					} else {
						this.$message.error('无相关房源')
					}
				})
			},
			handleClose(done) { //当筛选抽屉关闭
				this.show = false
				this.currentPage = 1;
				this.$axios.post(`${this.common.backendURL}/api/house/data?curPage=1&limit=${this.pageSize}
				`, this.postform).then(res => {
					if (res.data.msg != "0") {
						this.total = parseInt(res.data.msg)
						this.housesData = res.data.data
						this.common.setTime(() => {
							this.show = true
						}, 200)
					} else {
						this.$message.error('无相关房源')
					}
				})
				this.cascaderDisabled = false
				done()
			},
			onClickDrawer() {
				if (this.query.by == '通勤时间') {
					this.cascaderDisabled = true
				}
				this.drawer = !this.drawer
			}
		},
		components: {
			OneHouse,
			RecommendedListing
		}
	}
</script>

<style scoped>
	.infotable {
		width: 1060px;
		height: 580px;
		padding-left: 20px;
		margin: 0 auto;
		overflow: hidden;
	}


	.infotable>div {
		margin-right: 20px;
		margin-top: 20px;
		float: left;
	}

	/* .infotable>div:nth-child(4n) {
		margin-right: 0;
	}
 */
	.search {
		width: 1060px;
		margin: 0 auto;
	}

	.search .input {
		width: 300px;
		float: right;
	}

	.info {
		transition: 0.3s;
		/* 设置变换的过渡时间为0.3秒 */
	}

	.info:hover {
		/* 当鼠标悬停在图片上时 */
		transform: scale(1.1);
		/* 让图片放大1.1倍 */
	}
</style>