<template>
	<div @click="handleClick">
		<el-card :body-style="{ padding: '0px' }">
			<div style="width: 240px;height: 180px;" v-if="haspicture">
				<img :src="src" class="image">
			</div>
			<div style="width: 240px; height: 180px;" v-if="!haspicture">
				<el-empty :image-size="75" description="未上传图片"></el-empty>
			</div>
			<div style="padding: 14px;">
				<span style="text-overflow: ellipsis; white-space: nowrap;">{{address}}</span>
				<div class="bottom" style="margin-top: 10px; overflow: hidden;">
					<span style="float: left;color: rgb(64,158,255);"><b>￥{{price}}元/月</b></span>
					<span style="float: right;">{{addName}}</span>
					<i style="float: right;" class="el-icon-user-solid"></i>
				</div>
			</div>
		</el-card>
	</div>
</template>

<script>
	export default {
		props: {
			index: Number
		},
		data() {
			return {
				src: '', //图片文件名
				address: '',
				price: 0,
				addName: '',
				haspicture: true,
			}
		},
		created() {
			if (this.$parent.housesData[this.index].pictureList != "[]") {
				var a = JSON.parse(this.$parent.housesData[this.index].pictureList)
				this.src = this.common.pictureURL + a[0].r
			} else {
				this.haspicture = false
			}
			this.address = this.$parent.housesData[this.index].address
			this.price = this.$parent.housesData[this.index].price
			this.addName = this.$parent.housesData[this.index].addName
		},
		methods: {
			handleClick() {


				if (this.$parent.name == 'HouseManagement' || this.$parent.name == 'OrderManagement') {
					this.$axios.get(this.common.backendURL + '/api/user/checkLoginState').then(res => {
						this.$router.push({
							name: 'house',
							params: {
								index: this.$parent.housesData[this.index].id,
								isAdmin: true,
								userid: res.data.data.id
							}
						})
					})
				} else {
					this.$axios.get(this.common.backendURL + '/api/user/checkLoginState').then(res => {
						this.$router.push({
							name: 'userhouse',
							params: {
								index: this.$parent.housesData[this.index].id,
								isAdmin: false,
								userid: res.data.data.id
							}
						})
					})

				}
			}
		},
		computed: {

		}
	}
</script>

<style scoped>
	.image {
		display: block;
		width: 100%;
		height: 100%;
		object-fit: cover;
	}

	.el-card {
		width: 240px;
		display: block;
		/* float: left; */
		-webkit-user-select: none;
		-moz-user-select: none;
		-ms-user-select: none;
		user-select: none;
		cursor: pointer;
	}
</style>