<!-- 管理端用户管理模块 -->
<template>
	<div>
		<el-dialog title="编辑用户" :visible.sync="dialogVisible" width="350px">
			<el-form ref="addform" label-width="80px" :inline="true" class="login_container" :model="form"
				:rules="rules">
				<el-form-item label="用户名" prop="username">
					<el-input v-model="form.username" placeholder="请输入用户名"></el-input>
				</el-form-item>
				<el-form-item label="姓名" prop="name">
					<el-input v-model="form.name" placeholder="请输入姓名"></el-input>
				</el-form-item>
				<el-form-item v-if="!passwordInputDisabled" label="密码" prop="password">
					<el-input type="password" v-model="form.password" placeholder="请输入密码"></el-input>
				</el-form-item>
				<el-form-item v-if="!passwordInputDisabled" label="确认密码" prop="confirmPassword">
					<el-input type="password" v-model="form.confirmPassword" placeholder="请确认密码"></el-input>
				</el-form-item>
				<el-form-item label="手机号" prop="phone">
					<el-input class="phone" v-model="form.phone" placeholder="请输入手机号"></el-input>
				</el-form-item>
				<el-form-item>
					<el-switch style="margin-left: 160px;" v-model="enable" active-text="启用" inactive-text="禁用">
					</el-switch>
				</el-form-item>
			</el-form>
			<span slot="footer" class="dialog-footer">
				<el-button @click="onClickDialogCancel">取 消</el-button>
				<el-button type="primary" @click="onClickDialogConfirm">确 定</el-button>
			</span>
		</el-dialog>

		<div class="manage_header">
			<el-button type="primary" @click="onClickAddButton" size="medium">+ 新增</el-button>
			<el-input @change="handleInputChange" placeholder="搜索用户名/手机号..." v-model="queryString">
				<el-button slot="append" icon="el-icon-search"></el-button>
			</el-input>
		</div>

		<div class="user_table"
			style="margin-top: 20px; box-shadow: 0 2px 4px rgba(0, 0, 0, .12), 0 0 6px rgba(0, 0, 0, .04)">
			<el-table stripe :data="userTableData" style="width: 100%">
				<el-table-column prop="username" label="用户名" align="center">
				</el-table-column>
				<el-table-column prop="name" label="姓名" align="center">
				</el-table-column>
				<el-table-column prop="phone" label="手机号" align="center">
				</el-table-column>
				<el-table-column :formatter="Formatter" prop="enable" label="状态" align="center">
				</el-table-column>
				<el-table-column label="操作">
					<template slot-scope="scope">
						<el-button size="mini" @click="handleEdit(scope.$index, scope.row)">编辑</el-button>
						<el-button size="mini" type="danger" @click="handleDelete(scope.$index, scope.row)">删除
						</el-button>
					</template>
				</el-table-column>
			</el-table>
			<el-pagination align='center' @current-change="handleCurrentChange" :current-page="currentPage"
				 :page-size="pageSize" layout="total, prev, pager, next" :total="total">
			</el-pagination>
		</div>
	</div>
</template>

<script>
	export default {
		data() {
			return {
				dialogVisible: false, //新增用户对话框是否可见
				dialogUse: 'add', //对话框用途
				passwordInputDisabled: false, //对话框中密码输入框是否禁用
				userTableData: [], //用户表格信息
				currentPage: 1, // 当前页码
				total: 0,
				pageSize: 9, // 每页的数据条数
				queryString: '', //输入的搜索字符串
				form: {
					id: '',
					username: '',
					name: '',
					password: '',
					phone: '',
					confirmPassword: '',
				},
				enable: true, //账号启用开关
				rules: {
					name: [{
						required: true,
						trigger: 'blur',
						message: '请输入姓名'
					}],
					username: [{
						required: true,
						trigger: 'blur',
						message: '请输入用户名'

					}],
					password: [{
						required: true,
						trigger: 'blur',
						message: '请输入密码'

					}],
					confirmPassword: [{
						required: true,
						trigger: 'blur',
						message: '请确认密码'
					}],
					phone: [{
							required: true,
							trigger: 'blur',
							message: '请输入手机号'
						},
						{
							pattern: /^1(3|4|5|6|7|8)\d{9}$/,
							message: '请输入正确的手机号'
						}
					],
				}
			}
		},
		computed: {
			postform() {
				return {
					id: this.form.id,
					username: this.form.username,
					name: this.form.name,
					phone: this.form.phone,
					enable: this.enable ? 1 : 0,
				}
			}
		},
		methods: {
			//按下新增按钮
			onClickAddButton() {
				this.dialogUse = 'add'
				this.passwordInputDisabled = false
				this.dialogVisible = true
				this.clearForm();
			},
			//按下新增用户对话框中的取消按钮，重置表单
			onClickDialogCancel() {
				this.dialogVisible = false
				this.clearForm();
			},
			//按下新增用户对话框中的确认按钮
			onClickDialogConfirm() {
				this.$refs.addform.validate((valid) => {
					if (valid) {
						if (this.form.password != this.form.confirmPassword) {
							this.$message.error('两次输入的密码不一致');
							return;
						}
						var url = this.dialogUse == 'add' ? '/api/user/saveOne' : '/api/user/updateOne'
						var postbody = this.dialogUse == 'add' ? this.form : this.postform
						this.$axios.post(this.common.backendURL + url, postbody)
							.then(res => {
								if (res.data.code == 1) {
									this.$message.success('成功')
									this.$axios.get(this.common.backendURL + '/api/user/data?curPage=' + this
										.currentPage + '&limit=' + this.pageSize + '&queryString=' + this
										.queryString).then(res => {
										this.total = parseInt(res.data.msg)
										this.userTableData = res.data.data
									})
									this.dialogVisible = false
								} else {
									this.$message.error('用户名重复');
								}
							})

					} else {
						this.$message.error('表单填写不正确')
					}
				})
			},
			//用户表格启用状态显示转换
			Formatter(row, column, cellValue) {
				if (cellValue == '1') {
					return "已启用";
				} else {
					return "已禁用";
				}
			},
			//编辑用户
			handleEdit(index, row) {
				this.dialogUse = 'edit'
				this.$axios.get(this.common.backendURL + '/api/user/getById' + '?id=' + row.id).then(res => {
					if (res.data.code == 1) {
						this.form.username = res.data.data.username
						this.form.name = res.data.data.name
						this.form.id = res.data.data.id
						this.form.phone = res.data.data.phone
						this.enable = res.data.data.enable==1?true:false
						this.passwordInputDisabled = true;
						this.dialogVisible = true
					} else {
						this.$message.error(res.data.msg)
					}
				})
			},
			//删除用户
			handleDelete(index, row) {
				this.$axios.get(this.common.backendURL + '/api/user/delById' + '?id=' + row.id).then(res => {
					if (res.data.code == 1) {
						this.$message.success('删除成功')
						//刷新表格内容
						this.$axios.get(this.common.backendURL + '/api/user/data?curPage=' + this.currentPage +
							'&limit=' + this.pageSize + '&queryString=' + this.queryString).then(res => {
							this.total = parseInt(res.data.msg)
							this.userTableData = res.data.data
						})
					} else {
						this.$message.error(res.data.msg)
					}
				})
			},
			//清空新增用户表单
			clearForm() {
				this.form.id = ''
				this.form.username = ''
				this.form.name = ''
				this.form.password = ''
				this.form.phone = ''
				this.form.confirmPassword = ''
			},
			//当前页改变时触发 跳转其他页
			handleCurrentChange(val) {
				this.currentPage = val;
				this.$axios.get(this.common.backendURL + '/api/user/data?curPage=' + val + '&limit=' + this.pageSize +
					'&queryString=' + this.queryString).then(res => {
					this.userTableData = res.data.data
				})
			},
			handleInputChange() {
				this.$axios.get(this.common.backendURL + '/api/user/data?curPage=1&limit=' + this.pageSize +
					'&queryString=' + this.queryString).then(res => {
					this.total = parseInt(res.data.msg)
					this.userTableData = res.data.data
				})
			}
		},
		created() {
			this.$axios.get(this.common.backendURL + '/api/user/data?curPage=1&limit=' + this.pageSize + '&queryString=' +
				this.queryString).then(res => {
				this.total = parseInt(res.data.msg)
				this.userTableData = res.data.data
			})
		},
	}
</script>

<style scoped>
	.manage_header {
		overflow: hidden;
	}

	.manage_header>.el-button {
		float: left;
	}

	.manage_header>.el-input {
		width: 300px;
		float: right;
	}
</style>
