<template>
	<div class="wrapper">
		<span style="margin-left: 10px;font-size: 20px;">我收藏的房源</span>
		<div class="infotable">
			<div class="info" v-for="(item,index) in housesData">
				<transition name="el-zoom-in-center">
					<one-house v-if="show" :index="index"></one-house>
				</transition>
			</div>
		</div>
		<div class="page">
			<el-pagination align="center" @current-change="handleCurrentChange" :current-page="currentPage"
				:page-size="pageSize" layout="total, prev, pager, next" :total="total"></el-pagination>
		</div>
	</div>
</template>

<script>
	import OneHouse from '../components/OneHouse.vue'
	export default {
		mounted() {
			this.$emit('changeIndex', '我的收藏')
		},
		activated() {
			this.show = false
			this.$axios.get(this.common.backendURL + '/api/user/listCollection?curPage=' + this.currentPage + '&limit=' + this
				.pageSize).then(res => {
				if (res.data.code == 1 && res.data.msg != '0') {
					this.housesData = res.data.data
					this.total = parseInt(res.data.msg)
					this.common.setTime(() => {
						this.show = true
					}, 200)
				} else {
					this.$message.error('收藏夹为空')
				}
			})
		},
		data() {
			return {
				housesData: [],
				show: false,
				currentPage: 1,
				pageSize: 8,
				total: 0
			}
		},
		methods: {
			handleCurrentChange(val) {
				this.show = false
				this.currentPage = val;
				this.$axios.get(this.common.backendURL + '/api/user/listCollection?curPage=' + this.currentPage + '&limit=' +
					this.pageSize).then(res => {
					if (res.data.code == 1 && res.data.msg != '0') {
						this.housesData = res.data.data
						this.total = parseInt(res.data.msg)
						this.common.setTime(() => {
						this.show = true
						}, 200)
					} else {
						this.$message.error('收藏夹为空')
					}
				})
			}

		},
		components: {
			OneHouse
		}
	}
</script>

<style scoped>
	.wrapper {
		width: 1060px;
		margin: 0 auto;
	}

	.infotable {
		width: 100%;
		height: 580px;
		padding-left: 20px;
		margin: 0 auto;
		overflow: hidden;
	}


	.infotable>div {
		margin-right: 20px;
		margin-top: 20px;
		float: left;
	}

	.info {
		transition: 0.3s;
		/* 设置变换的过渡时间为0.3秒 */
	}

	.info:hover {
		/* 当鼠标悬停在图片上时 */
		transform: scale(1.1);
		/* 让图片放大1.1倍 */
	}
</style>