<template>
	<div id="app">
		<el-row>
			<el-col :span="12">
				<el-card class="box-card">
					<div style="text-align: center;font-weight: bold;margin-bottom: 20px;font-size: 18px;">添加房源</div>
					<el-form ref="addform" :model="form" label-width="80px" size="small" :rules="rules">
						<el-form-item label="房屋简介">
							<el-input :rows="3" placeholder="请输入房屋介绍" maxlength="200" type="textarea" v-model="form.description"
								show-word-limit></el-input>
						</el-form-item>
						<el-form-item label="所在地" prop="location">
							<el-cascader :options="options" v-model="form.selectedOptions">
							</el-cascader>
						</el-form-item>
						<el-form-item label="小区名称" prop="address">
							<el-autocomplete class="inline-input" v-model="form.address" :fetch-suggestions="querySearch"
								placeholder="请输入小区名称并选择" :trigger-on-focus="false" @select="handleSelect"></el-autocomplete>
						</el-form-item>
						<el-form-item label="详细地址" prop="detailedAddress">
							<el-input placeholder="请输入详细地址" v-model="form.detailedAddress"></el-input>
						</el-form-item>

						<el-form-item label="期望租金" prop="price">
							<el-input oninput="value=value.replace(/[^0-9.]/g,'')" placeholder="请输入期望租金" v-model="form.price">
								<template slot="prepend">￥</template>
								<template slot="append">元 / 月</template>
							</el-input>
						</el-form-item>
						<el-form-item label="面积" prop="area">
							<el-input oninput="value=value.replace(/[^0-9.]/g,'')" placeholder="请输入面积" v-model="form.area">
								<template slot="append">平方米</template>
							</el-input>
						</el-form-item>
						<el-form-item label="装修风格">
							<el-radio-group v-model="form.decorationStyle">
								<el-radio label="简装修"></el-radio>
								<el-radio label="精装修"></el-radio>
							</el-radio-group>
						</el-form-item>
						<el-form-item label="户型">
							<el-input-number size="small" v-model="form.rooms" :min="0" :max="10" label="房">
							</el-input-number>&nbsp;&nbsp;房&nbsp;&nbsp;
							<el-input-number size="small" v-model="form.halls" :min="0" :max="10" label="厅">
							</el-input-number>&nbsp;&nbsp;厅
							<el-input-number size="small" v-model="form.bathrooms" :min="0" :max="10" label="卫">
							</el-input-number>&nbsp;&nbsp;卫
						</el-form-item>
						<el-form-item label="房屋朝向" prop="orientation">
							<el-checkbox-group v-model="form.orientation">
								<el-checkbox label="北"></el-checkbox>
								<el-checkbox label="东"></el-checkbox>
								<el-checkbox label="南"></el-checkbox>
								<el-checkbox label="西"></el-checkbox>
							</el-checkbox-group>
						</el-form-item>
						<el-form-item label="上传照片">
							<el-upload ref="upload" :data="{msg:{owner:10000,path:'/fefsf'}}" :limit="limit" accept=".jpg,.png" :action="uploadImageUrl"
								list-type="picture-card" :auto-upload="true" :on-preview="handlePictureCardPreview"
								:on-remove="handleRemove" :before-upload="beforeUpload" :file-list="filelist"
								:on-success="onUploadSuccess">
								<i class="el-icon-plus"></i>
							</el-upload>
							<el-dialog :visible.sync="dialogVisible">
								<img width="100%" :src="dialogImageUrl" alt="">
							</el-dialog>
						</el-form-item>
						<el-button size="small" style="margin-left: 391px;" type="primary" @click="onClickAddButton">
							确认添加</el-button>
					</el-form>
				</el-card>
			</el-col>
			<el-col :span="12">
				<div style="width: 500px; height: 500px;" v-show="empty">
					<el-empty :image-size="250" description="请在左侧选择小区以显示地图"></el-empty>
				</div>
				<transition name="el-zoom-in-center">
					<div v-show="!nomap">
						<img :src="mapaddress" style="margin-left: 10px;">
						<div style="margin: 0 auto; text-align: center; margin-top: 20px;">
							经度：<el-tag><b>{{form.lng}}</b></el-tag>&nbsp;&nbsp;纬度：<el-tag><b>{{form.lat}}</b></el-tag>
						</div>
					</div>
				</transition>
			</el-col>
		</el-row>
	</div>
</template>

<script>
	import {
		regionData,
		CodeToText,
	} from 'element-china-area-data'
	export default {
		activated() {
			this.$emit('changeIndex', '添加房源')
		},
		data() {
			var validatePass = (rule, value, callback) => {
				if (this.form.selectedOptions == null) {
					callback(new Error('请选择'));
				} else {
					callback()
				}
			}

			return {
				rules: {
					location: [{
						required: true,
						validator: validatePass,
						trigger: 'blur',
						// message: '请选择'
					}],
					address: [{
						required: true,
						trigger: 'blur',
						message: '请输入并选择'
					}],
					detailedAddress: [{
						required: true,
						trigger: 'blur',
						message: '请输入'
					}],
					price: [{
						required: true,
						trigger: 'blur',
						message: '请输入'
					}],
					area: [{
						required: true,
						trigger: 'blur',
						message: '请输入'
					}],
					orientation: [{
						required: true,
						trigger: 'blur',
						message: '请输入'
					}],
				},
				empty: true, //是否显示空地图状态
				filelist: [],
				limit: 5, //图片最大上传数量
				nomap: true, //是否显示地图空状态
				mapaddress: '',
				options: regionData, //地区选择器类型
				addresslist: {}, //输入建议（百度api获取数据）
				dialogImageUrl: '', //预览的图片路径
				dialogVisible: false, //预览图片是否显示
				//uploadImageUrl: this.common.backendURL + '/api/house/uploadImage', //上传图片的接口地址
				uploadImageUrl: 'https://peirong.co:8443/lovelive/uploadImage',
				form: {
					selectedOptions: null, //选中的项目
					description: '',
					address: '',
					detailedAddress: '',
					decorationStyle: '简装修',
					area: '',
					rooms: 0,
					halls: 0,
					bathrooms: 0,
					price: 0,
					lat: 0,
					lng: 0,
					orientation: [],
					pictureList: [],
				}
			}
		},
		computed: {
			city() { //返回通过地区选择器选择的城市名
				return CodeToText[this.form.selectedOptions[1]] == '市辖区' ?
					CodeToText[this.form.selectedOptions[0]] : CodeToText[this.form.selectedOptions[1]]
			},
			postform() {
				return {
					description: this.form.description,
					price: this.form.price,
					longitude: this.form.lng,
					latitude: this.form.lat,
					province: this.form.selectedOptions[0],
					city: this.form.selectedOptions[1],
					region: this.form.selectedOptions[2],
					address: this.form.address,
					detailedAddress: this.form.detailedAddress,
					area: this.form.area,
					decorationStyle: this.form.decorationStyle == '简装修' ? 0 : 1,
					rooms: this.form.rooms,
					halls: this.form.halls,
					bathrooms: this.form.bathrooms,
					orientation: this.form.orientation.join(),
					pictureList: JSON.stringify(this.form.pictureList)
				}
			}
		},
		methods: {
			querySearch(queryString, cb) { //请求百度api取得地址输入建议列表
				this.$jsonp('http://api.map.baidu.com/place/v2/suggestion?query=' + queryString +
						'&region=' + this.city + '&city_limit=true&output=json&ak=' + this.common.ak)

					// this.$axios.get(this.common.backendURL+'/api/house/getRecommendList?query=' + queryString +
					// 		'&region=' + this.city + '&ak=' + this.common.ak)
					.then((response) => {
						this.addresslist = response.result
						var results = [];
						for (var i = 0; i < this.addresslist.length; i++) {
							results[i] = {
								"value": this.addresslist[i].name,
								"index": i,
							};
						}
						// 调用 callback 返回建议列表的数据
						cb(results);
					})
			},
			handleSelect(item) {
				this.empty = false
				this.nomap = true
				this.form.lat = this.addresslist[item.index].location.lat
				this.form.lng = this.addresslist[item.index].location.lng
				this.mapaddress = 'http://api.map.baidu.com/staticimage/v2?ak=' + this.common.ak + '&center=' +
					this.form.lng + ',' + this.form.lat + '&width=500&height=500&zoom=16&copyright=1&markers=' + this.form
					.lng + ',' + this.form.lat
				this.common.setTime(() => {
					this.nomap = false
				}, 300)

			},
			handleRemove(file, fileList) {
				for (var i = 0; i < this.form.pictureList.length; i++) {
					if (this.form.pictureList[i].o == file.name) {
						this.$axios.get('https://peirong.co:8080/lovelive/deleteImage?fileName=' + this.form
							.pictureList[i].r).then((res) => {
							if (res.data.code == 1) {
								this.form.pictureList.splice(i, 1)
								this.$message.success('删除成功')
							} else {
								this.$message.error('删除失败')
							}
						})
						return
					}
				}
			},
			handlePictureCardPreview(file) {
				this.dialogImageUrl = file.url;
				this.dialogVisible = true;
			},
			beforeUpload(file) {
				const FILE_NAME = file.name
				if (FILE_NAME.substring(FILE_NAME.lastIndexOf('.')) !== '.jpg' && FILE_NAME.substring(FILE_NAME
						.lastIndexOf('.')) !== '.png') {
					this.$message.warning('仅支持.jpg和.png文件')
					return false
				}
				const isLt1M = file.size / 1024 / 1024 < 5
				if (isLt1M) {
					return true
				}
				this.$message.warning('请上传不超过5M的文件.')
				return false
			},
			onUploadSuccess(response, file, fileList) {
				this.form.pictureList.push({
					o: file.name,
					r: response.data
				}); //o:源文件名 r:服务端实际文件名
			},
			onClickAddButton() {
				this.$refs.addform.validate(valid => {
					if (valid) {
						this.$axios.post(this.common.backendURL + '/api/house/addHouse', this.postform)
							.then(
								() => {
									this.$alert('添加成功', '提示', {
										confirmButtonText: '确定',
										callback: action => { //重置表单
											this.form = {
												selectedOptions: [], //选中的项目
												description: '',
												address: '',
												detailedAddress: '',
												decorationStyle: '简装修',
												area: '',
												rooms: 0,
												halls: 0,
												bathrooms: 0,
												price: 0,
												lat: 0,
												lng: 0,
												orientation: [],
												pictureList: [],
											};
											this.filelist = []
											this.nomap = true
											this.mapaddress = ''
											this.addresslist = {}
											this.dialogImageUrl = ''
											this.dialogVisible = false
										}
									});
								})
					}
				})
			}
		},
	}
</script>

<style scoped>
	.form {}

	#app {
		width: 1024px;
		margin: 0 auto;
	}

	.el-autocomplete {
		width: 391px;
	}

	.el-cascader {
		width: 391px;
	}
</style>