<template>
	<div class="main">
		<el-divider></el-divider>
		<span style="margin-left: 10px;font-size: 20px;">根据您的偏好推荐</span>
		<div class="infotable">
			<div class="info" v-for="(item,index) in housesData">
				<transition name="el-zoom-in-center">
					<one-house v-if="show" :index="index"></one-house>
				</transition>
			</div>
		</div>
	</div>
</template>

<script>
	import OneHouse from '../components/OneHouse.vue'
	export default {
		data() {
			return {
				housesData: [],
				show: true,
			}
		},
		activated() {
			this.show = false
			this.$axios.get(`${this.common.backendURL}/api/house/listRecommendHouse`).then(res=>{
				this.housesData = res.data.data
				this.show = true
			})
		},
		components: {
			OneHouse
		}
	}
</script>

<style scoped>
	.main {
		width: 1060px;
		margin: 0 auto;
	}
	
	.infotable {
		width: 100%;
		/* height: 580px; */
		padding-left: 20px;
		margin: 0 auto;
		overflow: hidden;
	}
	
	
	.infotable>div {
		margin-right: 20px;
		margin-top: 20px;
		float: left;
	}
	
	.info {
		transition: 0.3s;
		/* 设置变换的过渡时间为0.3秒 */
	}
	
	.info:hover {
		/* 当鼠标悬停在图片上时 */
		transform: scale(1.1);
		/* 让图片放大1.1倍 */
	}
</style>